        import io.micronaut.serde.ObjectMapper
import org.slf4j.LoggerFactory

void sendPost(String URL, Object body) {
        // POST
            def post = new URL(URL).openConnection()
            def logger = LoggerFactory.getLogger(this.class)



            ObjectMapper mapper = ObjectMapper.getDefault()
            def bodyText = mapper.writeValueAsString(body)
            logger.debug("{}",bodyText)
            post.setRequestMethod("POST")
            post.setDoOutput(true)
            post.setRequestProperty("Content-Type", "application/json")
            post.getOutputStream().write(bodyText.getBytes("UTF-8"))
            def postRC = post.getResponseCode()
            logger.info("Response code {}",postRC)

        }

VISIT_PLACED_IN_QUEUE.scriptCode:
def ticket = eventBody.body.ticket
def queueId = eventBody.body.queueId
def queueName = eventBody.body?.events?.last()?.parameters?.queueName
def serviceId = eventBody.body?.currentService?.id
def serviceName = eventBody.body?.currentService?.name

devices.values().stream().map { m -> m.deviceParamValues }.forEach { device ->
    def logger = LoggerFactory.getLogger(this.class)
    logger.info("VISIT_PLACED_IN_QUEUE: ticket={}, queueId={}, serviceId={}", ticket, queueId, serviceId)

    ru.aritmos.keycloak.service.KeyCloackClient keyCloackClient =
            beans.get("ru.aritmos.keycloak.service.KeyCloackClient")

    Properties props2 = new Properties()
    def smtpProps = systemConfiguration?.smtpServerProps ?: [:]
    smtpProps.each { key, param ->
        def value = param?.value
        props2.put(key, value)
        logger.debug("SMTP prop {} = {}", key, value)
    }

    def renderTemplate = { template, values ->
        def result = (template ?: "").toString()
        values?.each { entry ->
            result = result.replace("{{${entry.key}}}", (entry.value ?: "").toString())
        }
        return result
    }

    def placeholders = [
            ticket     : ticket?.toString() ?: "",
            queueId    : queueId?.toString() ?: "",
            queueName  : queueName?.toString() ?: "",
            serviceId  : serviceId?.toString() ?: "",
            serviceName: serviceName?.toString() ?: ""
    ]

    /**
     * Нормализуем конфигурацию уведомления к виду:
     *  - subject (String)
     *  - body (String)
     *  - roles (List<String>) или emails (List<String>)
     * Поддерживаем обратную совместимость:
     *  - Map.Entry<String, List<String>> (старый формат ролей: key=шаблон, value=роли)
     *  - Map<String, List<String>> (старый формат прямых email: {"Subject": ["a@b"]})
     */
    def coerceNotificationCfg = { cfg ->
        if (cfg == null) {
            return null
        }
        if (cfg instanceof Map.Entry) {
            def text = cfg.key?.toString()
            return [subject: text, body: text, roles: (cfg.value ?: [])]
        }
        if (cfg instanceof Map) {
            // Новый формат: {subject, body, roles/emails}
            if (cfg.containsKey("subject") || cfg.containsKey("body") || cfg.containsKey("roles") || cfg.containsKey("emails")) {
                def subject = cfg.get("subject")
                def body = cfg.get("body")
                if (subject == null && body != null) {
                    subject = body
                }
                if (body == null && subject != null) {
                    body = subject
                }
                return [
                        subject: subject?.toString(),
                        body   : body?.toString(),
                        roles  : cfg.get("roles"),
                        emails : cfg.get("emails")
                ]
            }
            // Старый формат прямых email: {"Subject": ["a@b"]}
            if (!cfg.isEmpty()) {
                def entry = cfg.entrySet().iterator().next()
                def subject = entry.key?.toString()
                def emails = entry.value
                return [subject: subject, body: subject, emails: emails]
            }
        }
        return null
    }

    def normalizeRecipients = { obj ->
        if (obj == null) {
            return []
        }
        if (obj instanceof Collection) {
            return obj.collect { it?.toString() }.findAll { it }.unique()
        }
        return [obj.toString()]
    }

    def sendNotification = { cfg, recipients ->
        def r = normalizeRecipients(recipients)
        if (cfg == null || r.isEmpty()) {
            return
        }

        def subjectTemplate = cfg.subject ?: "Уведомление: талон {{ticket}}"
        def bodyTemplate = cfg.body ?: subjectTemplate
        def subject = renderTemplate(subjectTemplate, placeholders)
        def body = renderTemplate(bodyTemplate, placeholders)
        if (!subject?.toString()?.trim()) {
            subject = "Уведомление: талон ${ticket}".toString()
        }
        if (!body?.toString()?.trim()) {
            body = subject
        }

        logger.info("Отправка email: recipients={}, subject={}", r, subject)
        send(props2, r, subject, body)
    }

    // 1) По ролям: очередь
    def queueRolesCfgRaw = device.get("arriveRolesByQueue")?.value?.get(queueId)
    def queueRolesCfg = coerceNotificationCfg(queueRolesCfgRaw)
    def queueRoles = normalizeRecipients(queueRolesCfg?.roles)
    def queueRoleRecipients = (queueRoles ? (keyCloackClient.getAllEmailsByRoles(queueRoles) ?: []) : [])
    sendNotification(queueRolesCfg, queueRoleRecipients)

    // 2) По ролям: услуга
    def serviceRolesCfgRaw = device.get("arriveRolesByService")?.value?.get(serviceId)
    def serviceRolesCfg = coerceNotificationCfg(serviceRolesCfgRaw)
    def serviceRoles = normalizeRecipients(serviceRolesCfg?.roles)
    def serviceRoleRecipients = (serviceRoles ? (keyCloackClient.getAllEmailsByRoles(serviceRoles) ?: []) : [])
    sendNotification(serviceRolesCfg, serviceRoleRecipients)

    // 3) Прямые email: очередь
    def queueEmailsCfgRaw = device.get("arriveEmailsByQueue")?.value?.get(queueId)
    def queueEmailsCfg = coerceNotificationCfg(queueEmailsCfgRaw)
    sendNotification(queueEmailsCfg, queueEmailsCfg?.emails)

    // 4) Прямые email: услуга
    def serviceEmailsCfgRaw = device.get("arriveEmailsByService")?.value?.get(serviceId)
    def serviceEmailsCfg = coerceNotificationCfg(serviceEmailsCfgRaw)
    sendNotification(serviceEmailsCfg, serviceEmailsCfg?.emails)
}

