import jakarta.mail.*;
import jakarta.mail.internet.InternetAddress;
import jakarta.mail.internet.MimeMessage;
import org.slf4j.LoggerFactory

def void addEmail(Set recipients, def email) {
    if (!email) {
        return
    }
    recipients.add(email.toString())
}

def void collectEmails(Set recipients, def source) {
    if (!source) {
        return
    }
    if (source instanceof Collection) {
        source.each { collectEmails(recipients, it) }
        return
    }
    if (source instanceof Map) {
        source.each { key, value ->
            if (key == "userEmail" || key == "email") {
                addEmail(recipients, value)
            } else {
                collectEmails(recipients, value)
            }
        }
        return
    }
    try {
        source.properties?.each { key, value ->
            if (key == "class" || value == source) {
                return
            }
            if (key == "userEmail" || key == "email") {
                addEmail(recipients, value)
            } else {
                collectEmails(recipients, value)
            }
        }
    } catch (ignored) {
    }
}

def String renderTemplate(String templateText, Map values) {
    def result = templateText ?: ""
    values?.each { entry ->
        result = result.replace("{{${entry.key}}}", entry.value ?: "")
    }
    return result
}

def String formatStaffList(def list, Closure<String> formatter) {
    if (!list) {
        return "нет данных"
    }
    def rendered = list.collect { formatter(it) }.findAll { it }
    return rendered.isEmpty() ? "нет данных" : rendered.join(System.lineSeparator())
}

def String resolveServicePointStatus(def eventPayload) {
    if ("true".equalsIgnoreCase(eventPayload.servicePointOnBreak?.toString())) {
        return "на перерыве"
    }
    if ("true".equalsIgnoreCase(eventPayload.servicePointIsServing?.toString())) {
        return "обслуживает клиента"
    }
    return "свободно"
}

def void send(Properties props,List<String> recipients,String subject,String body){
    def logger = LoggerFactory.getLogger(this.class)
    logger.info("Подготовка к отправке письма: получатели={}, тема={}", recipients, subject)
    logger.debug("Тело письма перед отправкой: {}", body)
    logger.debug("SMTP конфигурация: host={}, port={}, starttls={}", props.getProperty("mail.smtp.host"), props.getProperty("mail.smtp.port"), props.getProperty("mail.smtp.starttls.enable"))
    def username = props.getProperty("mail.smtp.username")
    def password = props.getProperty("mail.smtp.password")

    def session = jakarta.mail.Session.getInstance(props, new jakarta.mail.Authenticator() {
        protected jakarta.mail.PasswordAuthentication getPasswordAuthentication() {
            return new jakarta.mail.PasswordAuthentication(username, password)
        }
    })

    def message = new jakarta.mail.internet.MimeMessage(session)
    message.setFrom(new jakarta.mail.internet.InternetAddress(props["from"]))
    recipients.forEach {recipient->
        message.addRecipients(jakarta.mail.Message.RecipientType.TO, recipient)
    }
    message.setSubject(subject)
    message.setText(body)

    jakarta.mail.Transport.send(message)
    logger.info("Письмо успешно отправлено {} получателям", recipients.size())

}

