        import io.micronaut.serde.ObjectMapper
import org.slf4j.LoggerFactory

void sendPost(String URL, Object body) {
        // POST
            def post = new URL(URL).openConnection()
            def logger = LoggerFactory.getLogger(this.class)



            ObjectMapper mapper = ObjectMapper.getDefault()
            def bodyText = mapper.writeValueAsString(body)
            logger.debug("{}",bodyText)
            post.setRequestMethod("POST")
            post.setDoOutput(true)
            post.setRequestProperty("Content-Type", "application/json")
            post.getOutputStream().write(bodyText.getBytes("UTF-8"))
            def postRC = post.getResponseCode()
            logger.info("Response code {}",postRC)

        }

