import org.slf4j.LoggerFactory

static def sendCommand(ip, port, command) {
    def logger = LoggerFactory.getLogger(this.class)
    logger.info("Sending command " + command)
    if (command == null || command.toString().isBlank()) {
        logger.warn("Пустая команда для дисплея {}:{}", ip, port)
        return
    }
    InetAddress address = InetAddress.getByName(ip)
    InetSocketAddress b = new InetSocketAddress(address, port)
    DatagramSocket displaySocket = new DatagramSocket()
    displaySocket.connect(b)
    displaySocket.setSoTimeout(100000)


    DatagramPacket pack = new DatagramPacket(command.getBytes(), command.getBytes().length, address, port)
    displaySocket.send(pack)
    displaySocket.disconnect()

}

static def clear(ip, port, zone) {
    def logger = LoggerFactory.getLogger(this.class)
    sendCommand(ip, port, String.format("at+im=0,%s", zone))
}

static def clear(ip, port) {
    sendCommand(ip, port, "at+im=0")
}

static def setZone(ip, port, zone, x1, y1, x2, y2) {
    sendCommand(ip, port, String.format("at+im=4,%s,%s,%s,%s,%s", zone, x1, y1, x2, y2))
}

static def sendText(ip, port, zone, color, effectColor, font, effect, repeat, effectSpeed, align, code, text) {
    sendCommand(ip, port, String.format("at+im=1,%s,3,%s,%s,%s,%s,50,%s,1,%s,%s,1,%s", font, color, effectColor, effect, repeat, effectSpeed, align, zone, text))
}
static def sendText(ip, port, zone, color, effectColor, font, effect, repeat, effectSpeed, align, text) {
    sendCommand(ip, port, String.format("at+im=1,%s,3,%s,%s,%s,%s,50,%s,1,%s,%s,1,%s", font, color, effectColor, effect, repeat, effectSpeed, align, zone, text))
}

static def sendMarque(ip, port, zone, color, font, speed, repeat, align, code, text) {
    sendCommand(ip, port, String.format("at+im=5,%s,3,%s,%s,50,%s,%s,%s,%s", font, color, repeat, speed, code, zone, text))
}

